import type { ReactNode } from "react";
import { cn } from "../lib/utils";

interface ThemeOptionProps {
  icon: ReactNode;
  label: string;
  description: string;
  active: boolean;
  onSelect: () => void;
}

function ThemeOptionInner({
  icon,
  label,
  description,
  active,
  onSelect,
}: ThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={active}
      onClick={onSelect}
      className={cn(
        "theme-widget-option",
        active && "theme-widget-option--active"
      )}
    >
      <span
        className={cn(
          "theme-widget-option-icon",
          active && "theme-widget-option-icon--active"
        )}
      >
        {icon}
      </span>
      <span className="theme-widget-option-text">
        <span
          className={cn(
            "theme-widget-option-label",
            active && "theme-widget-option-label--active"
          )}
        >
          {label}
        </span>
        <span className="theme-widget-option-desc">{description}</span>
      </span>
      <span
        className={cn(
          "theme-widget-radio",
          active && "theme-widget-radio--active"
        )}
      >
        {active && <span className="theme-widget-radio-dot" />}
      </span>
    </button>
  );
}

ThemeOptionInner.displayName = "ThemeOption";

export const ThemeOption = ThemeOptionInner;
